func TestLoadEnvBearerOrCookieAuth(t *testing.T) {
	t.Setenv("ALLTRAILS_CONFIG", t.TempDir()+"/missing.toml")
	t.Setenv("ALLTRAILS_ACCESS_TOKEN", "token-123")
	t.Setenv("ALLTRAILS_COOKIE", "at_session=abc")
	t.Setenv("ALLTRAILS_CSRF_TOKEN", "csrf-123")

	cfg, err := Load("")
	if err != nil {
		t.Fatalf("Load returned error: %v", err)
	}
	if got := cfg.AuthHeader(); got != "Bearer token-123" {
		t.Fatalf("AuthHeader = %q, want Bearer token-123", got)
	}
	if got := cfg.AuthSource; got != "env:ALLTRAILS_ACCESS_TOKEN" {
		t.Fatalf("AuthSource = %q, want env token source", got)
	}
	if got := cfg.Headers["Cookie"]; got != "at_session=abc" {
		t.Fatalf("Cookie header = %q", got)
	}
	if got := cfg.Headers["x-csrftoken"]; got != "csrf-123" {
		t.Fatalf("x-csrftoken header = %q", got)
	}
}

